+/// Get available disk space in MB
+fn get_available_space_mb() -> Option<u64> {
+    #[cfg(unix)]
+    {
+        Command::new("df")
+            .args(["-m", "."])
+            .output()
+            .ok()
+            .and_then(|out| {
+                if out.status.success() {
+                    let stdout = String::from_utf8_lossy(&out.stdout);
+                    stdout
+                        .lines()
+                        .nth(1)
+                        .and_then(|line| line.split_whitespace().nth(3))
+                        .and_then(|s| s.parse().ok())
+                } else {
+                    None
+                }
+            })
+    }
+    #[cfg(not(unix))]
+    {
+        None
+    }
